// apiService.js

const BASE_URL = 'https://api.example.com';

// Token storage (in-memory; for production, use AsyncStorage or SecureStore)
let authToken = null;
let refreshToken = null;

// ─── Token Management ────────────────────────────────────────────────

const setTokens = (access, refresh) => {
  authToken = access;
  refreshToken = refresh;
};

const clearTokens = () => {
  authToken = null;
  refreshToken = null;
};

const getAuthToken = () => authToken;
const getRefreshToken = () => refreshToken;

// ─── Persistent Token Storage (AsyncStorage wrapper) ─────────────────

import AsyncStorage from '@react-native-async-storage/async-storage';

const persistTokens = async (access, refresh) => {
  try {
    await AsyncStorage.multiSet([
      ['@auth_token', access],
      ['@refresh_token', refresh],
    ]);
    setTokens(access, refresh);
  } catch (e) {
    console.error('Failed to persist tokens:', e);
  }
};

const loadTokens = async () => {
  try {
    const values = await AsyncStorage.multiGet(['@auth_token', '@refresh_token']);
    const access = values[0][1];
    const refresh = values[1][1];
    if (access && refresh) {
      setTokens(access, refresh);
    }
    return { access, refresh };
  } catch (e) {
    console.error('Failed to load tokens:', e);
    return { access: null, refresh: null };
  }
};

const removePersistentTokens = async () => {
  try {
    await AsyncStorage.multiRemove(['@auth_token', '@refresh_token']);
    clearTokens();
  } catch (e) {
    console.error('Failed to remove tokens:', e);
  }
};

// ─── Custom Error Class ──────────────────────────────────────────────

class ApiError extends Error {
  constructor(message, status, data) {
    super(message);
    this.name = 'ApiError';
    this.status = status;
    this.data = data;
  }
}

// ─── Core Request Handler ────────────────────────────────────────────

const request = async (endpoint, options = {}, retry = true) => {
  const url = `${BASE_URL}${endpoint}`;

  const headers = {
    'Content-Type': 'application/json',
    Accept: 'application/json',
    ...options.headers,
  };

  // Attach auth token if available
  if (authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }

  const config = {
    method: options.method || 'GET',
    headers,
    ...(options.body ? { body: JSON.stringify(options.body) } : {}),
  };

  // Timeout wrapper for fetch (cross-platform compatible)
  const timeout = options.timeout || 15000;

  const fetchWithTimeout = (url, config, timeout) => {
    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => {
        reject(new ApiError('Request timed out', 0, null));
      }, timeout);

      fetch(url, config)
        .then((response) => {
          clearTimeout(timer);
          resolve(response);
        })
        .catch((err) => {
          clearTimeout(timer);
          reject(err);
        });
    });
  };

  try {
    const response = await fetchWithTimeout(url, config, timeout);

    // Handle 204 No Content
    if (response.status === 204) {
      return { success: true, data: null, status: 204 };
    }

    let data;
    const contentType = response.headers.get('content-type');
    if (contentType && contentType.includes('application/json')) {
      data = await response.json();
    } else {
      data = await response.text();
    }

    // Handle token expiration with automatic refresh
    if (response.status === 401 && retry && refreshToken) {
      const refreshed = await refreshAccessToken();
      if (refreshed) {
        return request(endpoint, options, false); // Retry once
      } else {
        await removePersistentTokens();
        throw new ApiError('Session expired. Please log in again.', 401, data);
      }
    }

    if (!response.ok) {
      const errorMessage =
        data?.message || data?.error || `Request failed with status ${response.status}`;
      throw new ApiError(errorMessage, response.status, data);
    }

    return { success: true, data, status: response.status };
  } catch (error) {
    if (error instanceof ApiError) {
      throw error;
    }

    // Network error (no internet, DNS failure, etc.)
    if (error.message === 'Network request failed') {
      throw new ApiError(
        'No internet connection. Please check your network and try again.',
        0,
        null
      );
    }

    throw new ApiError(error.message || 'An unexpected error occurred', 0, null);
  }
};

// ─── Token Refresh ───────────────────────────────────────────────────

const refreshAccessToken = async () => {
  try {
    const response = await fetch(`${BASE_URL}/auth/refresh`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Accept: 'application/json',
      },
      body: JSON.stringify({ refreshToken }),
    });

    if (!response.ok) {
      return false;
    }

    const data = await response.json();
    if (data.accessToken && data.refreshToken) {
      await persistTokens(data.accessToken, data.refreshToken);
      return true;
    }

    return false;
  } catch (error) {
    console.error('Token refresh failed:', error);
    return false;
  }
};

// ─── Authentication API ──────────────────────────────────────────────

const authApi = {
  /**
   * Register a new user
   */
  register: async (email, password, fullName) => {
    const result = await request('/auth/register', {
      method: 'POST',
      body: { email, password, fullName },
    });

    if (result.data.accessToken && result.data.refreshToken) {
      await persistTokens(result.data.accessToken, result.data.refreshToken);
    }

    return result;
  },

  /**
   * Login with email and password
   */
  login: async (email, password) => {
    const result = await request('/auth/login', {
      method: 'POST',
      body: { email, password },
    });

    if (result.data.accessToken && result.data.refreshToken) {
      await persistTokens(result.data.accessToken, result.data.refreshToken);
    }

    return result;
  },

  /**
   * Login with social provider (Google, Apple, etc.)
   */
  socialLogin: async (provider, providerToken) => {
    const result = await request('/auth/social', {
      method: 'POST',
      body: { provider, token: providerToken },
    });

    if (result.data.accessToken && result.data.refreshToken) {
      await persistTokens(result.data.accessToken, result.data.refreshToken);
    }

    return result;
  },

  /**
   * Logout the current user
   */
  logout: async () => {
    try {
      await request('/auth/logout', { method: 'POST' });
    } catch (error) {
      // Even if server logout fails, clear local tokens
      console.warn('Server logout failed:', error.message);
    } finally {
      await removePersistentTokens();
    }

    return { success: true };
  },

  /**
   * Request password reset
   */
  forgotPassword: async (email) => {
    return request('/auth/forgot-password', {
      method: 'POST',
      body: { email },
    });
  },

  /**
   * Reset password with token
   */
  resetPassword: async (token, newPassword) => {
    return request('/auth/reset-password', {
      method: 'POST',
      body: { token, newPassword },
    });
  },

  /**
   * Change password (authenticated)
   */
  changePassword: async (currentPassword, newPassword) => {
    return request('/auth/change-password', {
      method: 'POST',
      body: { currentPassword, newPassword },
    });
  },

  /**
   * Check if user is authenticated (has valid tokens)
   */
  isAuthenticated: () => {
    return !!authToken;
  },

  /**
   * Initialize auth state from persistent storage
   */
  initialize: async () => {
    const tokens = await loadTokens();
    return !!tokens.access;
  },
};

