  /**
   * Upload profile avatar (multipart form data)
   */
  uploadAvatar: async (imageUri) => {
    const formData = new FormData();
    const filename = imageUri.split('/').pop();
    const match = /\.(\w+)$/.exec(filename);
    const type = match ? `image/${match[1]}` : 'image/jpeg';

    formData.append('avatar', {
      uri: imageUri,
      name: filename,
      type,
    });

    const url = `${BASE_URL}/user/avatar`;
    const response = await fetch(url, {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${authToken}`,
        Accept: 'application/json',
        // Note: Do NOT set Content-Type for multipart/form-data;
        // fetch will set it automatically with the correct boundary
      },
      body: formData,
    });

    const data = await response.json();

    if (!response.ok) {
      throw new ApiError(
        data.message || 'Avatar upload failed',
        response.status,
        data
      );
    }

    return { success: true, data, status: response.status };
  },

